// app/sejours-enfants-ados/[id]/page.jsx
import { prisma } from "@/lib/prisma";
import { notFound } from "next/navigation";
import SejourDetailClient from "./SejourDetailClient"; // On importe ton grand fichier de design !

// ⚡ On s'assure d'avoir les données en temps réel
export const dynamic = "force-dynamic";

export default async function SejourPage({ params }) {
  // 1. On récupère l'ID du séjour dans l'URL
  const { id } = params;

  // 2. On demande à Neon (Prisma) de trouver le séjour correspondant
  const sejour = await prisma.sejour.findUnique({
    where: { id: id },
  });

  // Si on tape une fausse URL, on affiche une page 404
  if (!sejour) {
    notFound();
  }

  // 3. Bonus : on cherche 3 autres séjours de la même saison pour "À découvrir aussi"
  const autresSejours = await prisma.sejour.findMany({
    where: { 
      statut: "Publié",
      id: { not: id }, // On exclut le séjour actuel
      saison: sejour.saison 
    },
    take: 3
  });

  // 4. ON PASSE ENFIN LA VARIABLE "sejour" AU DESIGN ! 🎉
  return <SejourDetailClient sejour={sejour} autresSejours={autresSejours} />;
}